  // 5. Non-existent coupon
  console.log('\n--- Non-existent Coupon ---');
  const result4 = await system.redeemCoupon('DOESNOTEXIST', 'user_001');
  console.log('Non-existent coupon:', result4);

  // 6. Race condition test — simulate 20 concurrent users trying to redeem
  //    a coupon that only has 5 total redemptions
  console.log('\n--- Race Condition Test (20 concurrent users, 5 max redemptions) ---');

  const concurrentPromises = [];
  for (let i = 0; i < 20; i++) {
    concurrentPromises.push(
      system.redeemCoupon('SUMMER25', `race_user_${String(i).padStart(3, '0')}`)
    );
  }

  const raceResults = await Promise.all(concurrentPromises);

  const successCount = raceResults.filter(r => r.success).length;
  const failedCount = raceResults.filter(r => !r.success).length;

  console.log(`Results: ${successCount} successful, ${failedCount} rejected`);
  console.log(`Expected: ~4 successful (1 was already used by user_001), 16 rejected`);

  // Show breakdown of failures
  const errorBreakdown = {};
  raceResults.filter(r => !r.success).forEach(r => {
    errorBreakdown[r.errorCode] = (errorBreakdown[r.errorCode] || 0) + 1;
  });
  console.log('Error breakdown:', errorBreakdown);

  // 7. Stats
  console.log('\n--- Coupon Stats ---');
  const stats = await system.getCouponStats('SUMMER25');
  console.log('SUMMER25 stats:', JSON.stringify(stats, null, 2));

  // 8. Multi-use per user test
  console.log('\n--- Multi-use Per User (FLAT10, max 2 per user) ---');
  const multiUse1 = await system.redeemCoupon('FLAT10', 'user_multi');
  console.log('First use:', multiUse1);
